const fileName = items[0].json.name || items[0].json.file_name || '';
const baseName = fileName.replace(/\.[^/.]+$/, '');
const accountId = baseName.toLowerCase().replace(/[^a-z0-9]/g, '_');
return [{ json: { ...items[0].json, account_id: accountId, file_name: fileName, pipeline: 'demo' } }];

const fs = require('fs');
const filePath = items[0].json.path || `/data/input/demo/${items[0].json.file_name}`;
let transcript_text = '';
try {
  transcript_text = fs.readFileSync(filePath, 'utf8');
} catch(e) {
  transcript_text = `ERROR_READING_FILE: ${e.message}`;
}
return [{ json: { ...items[0].json, transcript_text } }];

let raw = '';
try {
  const body = items[0].json;
  raw = body.response || body.message?.content || JSON.stringify(body);
} catch(e) { raw = ''; }
raw = raw.replace(/```json|```/g, '').trim();
let memo;
try {
  memo = JSON.parse(raw);
} catch(e) {
  return [{ json: { parse_error: true, raw, account_id: items[0].json.account_id, transcript_text: items[0].json.transcript_text } }];
}
memo.account_id = items[0].json.account_id;
memo._version = 'v1';
memo._source = 'demo';
memo._created_at = new Date().toISOString();
return [{ json: { memo, account_id: items[0].json.account_id, transcript_text: items[0].json.transcript_text } }];

const memo = items[0].json.memo;
const required = ['company_name', 'business_hours', 'emergency_routing_rules'];
const missing = required.filter(f => !memo[f] || (typeof memo[f] === 'object' && !Array.isArray(memo[f]) && Object.keys(memo[f]).length === 0));
if (missing.length > 0) {
  memo.questions_or_unknowns = memo.questions_or_unknowns || [];
  missing.forEach(f => {
    if (!memo.questions_or_unknowns.includes(`Missing: ${f}`)) {
      memo.questions_or_unknowns.push(`Missing: ${f}`);
    }
  });
  memo._validation_warnings = missing;
}
return [{ json: { ...items[0].json, memo } }];

