const fileName = items[0].json.name || items[0].json.file_name || '';
const baseName = fileName.replace(/_onboarding\.[^/.]+$/, '').replace(/\.[^/.]+$/, '');
const accountId = baseName.toLowerCase().replace(/[^a-z0-9]/g, '_');
return [{ json: { ...items[0].json, account_id: accountId, file_name: fileName, pipeline: 'onboarding' } }];

const fs = require('fs');
const filePath = items[0].json.path || `/data/input/onboarding/${items[0].json.file_name}`;
let transcript_text = '';
try {
  transcript_text = fs.readFileSync(filePath, 'utf8');
} catch(e) {
  transcript_text = `ERROR_READING_FILE: ${e.message}`;
}
return [{ json: { ...items[0].json, transcript_text } }];

const fs = require('fs');
const accountId = items[0].json.account_id;
const memoPath = `/data/outputs/accounts/${accountId}/v1/memo.json`;
let v1_memo = null;
try {
  v1_memo = JSON.parse(fs.readFileSync(memoPath, 'utf8'));
} catch(e) {
  return [{ json: { ...items[0].json, load_error: true, error_message: `No v1 memo found for account_id '${accountId}'. Run Pipeline A first.` } }];
}
return [{ json: { ...items[0].json, v1_memo } }];

const fs = require('fs');
const logEntry = {
  timestamp: new Date().toISOString(),
  account_id: items[0].json.account_id,
  pipeline: 'B',
  status: 'halted',
  reason: items[0].json.error_message
};
fs.mkdirSync('/data/logs', { recursive: true });
fs.appendFileSync('/data/logs/pipeline_b.jsonl', JSON.stringify(logEntry) + '\n');
throw new Error(items[0].json.error_message);

let raw = '';
try {
  const body = items[0].json;
  raw = body.response || body.message?.content || JSON.stringify(body);
} catch(e) { raw = ''; }
raw = raw.replace(/```json|```/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  return [{ json: { ...items[0].json, parse_error: true, raw } }];
}
const patch = parsed.patch || {};
const change_reasons = parsed.change_reasons || {};
return [{ json: { ...items[0].json, patch, change_reasons } }];

const v1 = items[0].json.v1_memo;
const patch = items[0].json.patch || {};
const reasons = items[0].json.change_reasons || {};

const v2 = Object.assign({}, v1, patch);
v2._version = 'v2';
v2._updated_at = new Date().toISOString();
v2._source = 'onboarding';
v2._v1_created_at = v1._created_at;

const changelog = [];
for (const key of Object.keys(patch)) {
  changelog.push({
    field: key,
    old_value: v1[key] !== undefined ? v1[key] : null,
    new_value: patch[key],
    reason: reasons[key] || 'updated on onboarding call'
  });
}

return [{ json: { ...items[0].json, v2_memo: v2, changelog } }];

