const fs = require('fs');
const accountId = items[0].json.account_id;
const v2Dir = `/data/outputs/accounts/${accountId}/v2`;
const changelogDir = `/data/outputs/accounts/${accountId}`;
fs.mkdirSync(v2Dir, { recursive: true });

fs.writeFileSync(`${v2Dir}/memo.json`, JSON.stringify(items[0].json.v2_memo, null, 2));
fs.writeFileSync(`${v2Dir}/agent_spec.json`, JSON.stringify(items[0].json.agent_spec_v2, null, 2));

const changelogPayload = {
  account_id: accountId,
  v1_created_at: items[0].json.v1_memo?._created_at,
  v2_created_at: items[0].json.v2_memo._updated_at,
  changes: items[0].json.changelog
};
fs.writeFileSync(`${changelogDir}/changelog.json`, JSON.stringify(changelogPayload, null, 2));

return [{ json: { ...items[0].json, v2_memo_path: `${v2Dir}/memo.json`, v2_spec_path: `${v2Dir}/agent_spec.json`, changelog_path: `${changelogDir}/changelog.json` } }];

const fs = require('fs');
const logEntry = {
  timestamp: new Date().toISOString(),
  account_id: items[0].json.account_id,
  pipeline: 'B',
  status: 'success',
  changes_applied: items[0].json.changelog?.length || 0
};
fs.mkdirSync('/data/logs', { recursive: true });
fs.appendFileSync('/data/logs/pipeline_b.jsonl', JSON.stringify(logEntry) + '\n');
return [{ json: logEntry }];
